import json

def parse_tool_args(raw: str) -> tuple[dict | None, str | None]:
    """Returns (args, None) on success, (None, error_message) on failure."""
    try:
        args = json.loads(raw)
    except json.JSONDecodeError as e:
        return None, f"Malformed JSON in tool call: {e}"
    if not isinstance(args, dict):
        return None, f"Expected a JSON object, got {type(args).__name__}"
    return args, None

def dispatch(tool_call) -> str:
    args, err = parse_tool_args(tool_call.function.arguments)
    if err:
        return json.dumps({"error": err})
    return execute_tool(tool_call.function.name, args)

