import json
import jsonschema
from jsonschema import ValidationError, SchemaError

# The schema is the same object you pass to the LLM as "parameters"
SEARCH_SCHEMA = {
    "type": "object",
    "properties": {
        "query":      {"type": "string", "minLength": 1},
        "top_k":      {"type": "integer", "minimum": 1, "maximum": 20},
        "department": {"type": "string", "enum": ["finance", "hr", "legal", "engineering", "all"]},
        "include_metadata": {"type": "boolean"},
    },
    "required": ["query"],
    "additionalProperties": False,
}

def validate_args(args: dict, schema: dict) -> str | None:
    """Returns None if valid, or an error message string if invalid."""
    try:
        jsonschema.validate(args, schema)
        return None
    except ValidationError as e:
        # e.path gives the field path; e.message gives the failure reason
        field = " -> ".join(str(p) for p in e.path) or "root"
        return f"Validation error at '{field}': {e.message}"

# Full dispatch pipeline
def dispatch_search(raw_args: str) -> str:
    args, parse_err = parse_tool_args(raw_args)
    if parse_err:
        return json.dumps({"error": parse_err})

    schema_err = validate_args(args, SEARCH_SCHEMA)
    if schema_err:
        return json.dumps({"error": schema_err})

    return json.dumps(search_documents(**args))

