from pydantic import BaseModel, Field, field_validator, model_validator
from typing import Optional
import json

class SearchArgs(BaseModel):
    query: str = Field(min_length=1, description="Search query.")
    top_k: int = Field(default=5, ge=1, le=20)
    department: str = Field(default="all")
    include_metadata: bool = Field(default=False)

    @field_validator("department")
    @classmethod
    def valid_department(cls, v: str) -> str:
        allowed = {"finance", "hr", "legal", "engineering", "all"}
        v = v.lower().strip()
        if v not in allowed:
            raise ValueError(f"Must be one of {sorted(allowed)}, got {v!r}")
        return v

class DateRangeArgs(BaseModel):
    start_date: str
    end_date: str

    @model_validator(mode="after")
    def end_after_start(self) -> "DateRangeArgs":
        if self.end_date <= self.start_date:
            raise ValueError(f"end_date ({self.end_date}) must be after start_date ({self.start_date})")
        return self

def dispatch_with_pydantic(raw_args: str) -> str:
    try:
        args = SearchArgs.model_validate_json(raw_args)
    except Exception as e:
        return json.dumps({"error": f"Argument validation failed: {e}"})
    return json.dumps(search_documents(
        query=args.query,
        top_k=args.top_k,
        department=args.department,
        include_metadata=args.include_metadata,
    ))

