from datetime import date
import json

def validate_booking_args(args: dict) -> str | None:
    """Return error string or None if valid."""
    # Rule 1: check-out must be after check-in
    check_in = date.fromisoformat(args["check_in"])
    check_out = date.fromisoformat(args["check_out"])
    if check_out <= check_in:
        return f"check_out ({check_out}) must be after check_in ({check_in})"

    # Rule 2: check-in must not be in the past
    today = date.today()
    if check_in < today:
        return f"check_in ({check_in}) cannot be in the past (today is {today})"

    # Rule 3: room must exist in the database
    room = get_room(args["room_id"])
    if room is None:
        return f"Room '{args['room_id']}' does not exist"

    # Rule 4: room must be available for the requested period
    if not is_room_available(args["room_id"], check_in, check_out):
        return f"Room '{args['room_id']}' is not available from {check_in} to {check_out}"

    return None   # all checks passed

def dispatch_booking(raw_args: str) -> str:
    args, parse_err = parse_tool_args(raw_args)
    if parse_err:
        return json.dumps({"error": parse_err})

    schema_err = validate_args(args, BOOKING_SCHEMA)
    if schema_err:
        return json.dumps({"error": schema_err})

    semantic_err = validate_booking_args(args)
    if semantic_err:
        return json.dumps({"error": semantic_err})

    return json.dumps(create_booking(**args))

def format_validation_error(field: str, value, constraint: str, hint: str = "") -> dict:
    """Produce a structured, actionable error the LLM can act on."""
    msg = f"Invalid value for '{field}': {value!r}. {constraint}."
    if hint:
        msg += f" {hint}"
    return {"error": msg}

# Examples:
format_validation_error(
    "department", "Finance",
    'Must be lowercase',
    'Use "finance" instead of "Finance"'
)
# {'error': "Invalid value for 'department': 'Finance'. Must be lowercase. Use "finance" instead of "Finance"."}

format_validation_error(
    "check_in", "2024-01-01",
    'Cannot be in the past',
    'Use a date from today (2025-06-29) or later'
)
# {'error': "Invalid value for 'check_in': '2024-01-01'. Cannot be in the past. Use a date from today (2025-06-29) or later."}

import json
from typing import Callable

def make_validated_tool(
    schema: dict,
    model_cls,                         # Pydantic model
    business_validator: Callable,      # returns str | None
    executor: Callable,                # the actual tool function
):
    """
    Returns a dispatch function that validates args through all three layers
    and calls executor only when everything passes.
    """
    def dispatch(raw_args: str) -> str:
        # Layer 1: JSON parse
        args, err = parse_tool_args(raw_args)
        if err:
            return json.dumps({"error": err})

        # Layer 2: Schema validation
        schema_err = validate_args(args, schema)
        if schema_err:
            return json.dumps({"error": schema_err})

        # Layer 3: Pydantic (type coercion + field validators)
        try:
            validated = model_cls.model_validate(args)
        except Exception as e:
            return json.dumps({"error": f"Type validation: {e}"})

        # Layer 4: Business rules
        business_err = business_validator(validated.model_dump())
        if business_err:
            return json.dumps({"error": business_err})

        # All layers passed — execute
        try:
            result = executor(**validated.model_dump())
            return json.dumps(result, default=str)
        except Exception as e:
            return json.dumps({"error": f"Tool execution error: {e}"})

    return dispatch

# Wire it up:
dispatch_booking = make_validated_tool(
    schema=BOOKING_SCHEMA,
    model_cls=BookingArgs,
    business_validator=validate_booking_args,
    executor=create_booking,
)
